        foreach ($hardQuestions as $moduleId => $questions) {
            $module = Module::find($moduleId);
            if (!$module) continue;

            $this->command->info("Seeding hard questions for: {$module->name}");

            foreach ($questions as [$questionText, $answers, $correctIndex]) {
                $question = Question::create([
                    'question_text' => $questionText,
                    'type' => 'mcq',
                    'module_id' => $moduleId,
                    'difficulty' => 3,
                    'is_hard' => true,
                ]);

                foreach ($answers as $index => $answerText) {
                    Answer::create([
                        'question_id' => $question->id,
                        'answer_text' => $answerText,
                        'is_correct' => $index === $correctIndex,
                    ]);
                }
            }
        }

        $this->command->info("✅ Seeded 15 hard questions per module (90 total) for all 6 modules!");
